    lazy var secureSession: URLSession = {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.waitsForConnectivity = true
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        return URLSession(configuration: configuration, delegate: nil, delegateQueue: nil)
    }()
    
    /// URLSession configured for local network / IoT device connections (allows HTTP)
    lazy var localNetworkSession: URLSession = {
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 10
        configuration.timeoutIntervalForResource = 30
        configuration.waitsForConnectivity = false
        // Shorter timeout for local devices that may be offline
        return URLSession(configuration: configuration, delegate: LocalNetworkSessionDelegate(), delegateQueue: nil)
    }()
    
    private init() {}
}

// MARK: - Session Delegate for Local Network (handles self-signed certs)

class LocalNetworkSessionDelegate: NSObject, URLSessionDelegate {
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        // For local network devices with self-signed certificates, accept the certificate
        if challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
           let serverTrust = challenge.protectionSpace.serverTrust,
           isLocalNetworkHost(challenge.protectionSpace.host) {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
    
    private func isLocalNetworkHost(_ host: String) -> Bool {
        // Check for common local network IP ranges
        return host.hasPrefix("192.168.") ||
               host.hasPrefix("10.") ||
               host.hasPrefix("172.16.") ||
               host.hasPrefix("172.17.") ||
               host.hasPrefix("172.18.") ||
               host.hasPrefix("172.19.") ||
               host.hasPrefix("172.20.") ||
               host.hasPrefix("172.21.") ||
               host.hasPrefix("172.22.") ||
               host.hasPrefix("172.23.") ||
               host.hasPrefix("172.24.") ||
               host.hasPrefix("172.25.") ||
               host.hasPrefix("172.26.") ||
               host.hasPrefix("172.27.") ||
               host.hasPrefix("172.28.") ||
               host.hasPrefix("172.29.") ||
               host.hasPrefix("172.30.") ||
               host.hasPrefix("172.31.") ||
               host == "localhost" ||
               host == "127.0.0.1"
    }
}

// MARK: - HTTP Method Enum

enum HTTPMethod: String {
    case get = "GET"
    case post = "POST"
    case put = "PUT"
    case patch = "PATCH"
    case delete = "DELETE"
}

// MARK: - Network Error

enum NetworkError: Error, LocalizedError {
    case invalidURL
    case noData
    case decodingError(Error)
    case httpError(statusCode: Int, data: Data?)
    case networkUnavailable
    case timeout
    case connectionRefused
    case unknown(Error)
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .noData:
            return "No data received"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .httpError(let statusCode, _):
            return "HTTP error with status code: \(statusCode)"
        case .networkUnavailable:
            return "Network unavailable"
        case .timeout:
            return "Request timed out"
        case .connectionRefused:
            return "Connection refused - device may be offline"
        case .unknown(let error):
            return "Unknown error: \(error.localizedDescription)"
        }
    }
}

// MARK: - API Response

struct APIResponse<T> {
    let data: T
    let statusCode: Int
    let headers: [AnyHashable: Any]
}

// MARK: - HTTP Client Protocol

protocol HTTPClientProtocol {
    func request<T: Decodable>(
        url: String,
        method: HTTPMethod,
        headers: [String: String]?,
        body: Data?,
        responseType: T.Type
    ) async throws -> APIResponse<T>
    
    func requestRaw(
        url: String,
        method: HTTPMethod,
        headers: [String: String]?,
        body: Data?
    ) async throws -> APIResponse<Data>
}

// MARK: - HTTP Client

class HTTPClient: HTTPClientProtocol {
    
    private let networkConfig: NetworkConfiguration
    
    init(networkConfig: NetworkConfiguration = .shared) {
        self.networkConfig = networkConfig
    }
    
    // MARK: - Determine Session Based on URL
    
    private func session(for url: URL) -> URLSession {
        guard let host = url.host else {
            return networkConfig.secureSession
        }
        
        if isLocalNetwork(host: host) {
            return networkConfig.localNetworkSession
        }
        
        return networkConfig.secureSession
    }
    
    private func isLocalNetwork(host: String) -> Bool {
        return host.hasPrefix("192.168.") ||
               host.hasPrefix("10.") ||
               host.hasPrefix("172.16.") || host.hasPrefix("172.31.") ||
               host == "localhost" ||
               host == "127.0.0.1"
    }
    
    // MARK: - Generic Request with Decodable Response
    
    func request<T: Decodable>(
        url: String,
        method: HTTPMethod = .get,
        headers: [String: String]? = nil,
        body: Data? = nil,
        responseType: T.Type
    ) async throws -> APIResponse<T> {
        let rawResponse = try await requestRaw(url: url, method: method, headers: headers, body: body)
        
        do {
            let decoder = JSONDecoder()
            decoder.keyDecodingStrategy = .convertFromSnakeCase
            decoder.dateDecodingStrategy = .iso8601
            let decoded = try decoder.decode(T.self, from: rawResponse.data)
            return APIResponse(
                data: decoded,
                statusCode: rawResponse.statusCode,
                headers: rawResponse.headers
            )
        } catch {
            throw NetworkError.decodingError(error)
        }
    }
    
    // MARK: - Raw Data Request
    
    func requestRaw(
        url: String,
        method: HTTPMethod = .get,
        headers: [String: String]? = nil,
        body: Data? = nil
    ) async throws -> APIResponse<Data> {
        guard let url = URL(string: url) else {
            throw NetworkError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        request.httpBody = body
        
        // Default headers
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.setValue("application/json", forHTTPHeaderField: "Accept")
        
        // Custom headers
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        let selectedSession = session(for: url)
        
        do {
            let (data, response) = try await selectedSession.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw NetworkError.unknown(NSError(domain: "HTTPClient", code: -1))
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                throw NetworkError.httpError(statusCode: httpResponse.statusCode, data: data)
            }
            
            return APIResponse(
                data: data,
                statusCode: httpResponse.statusCode,
                headers: httpResponse.allHeaderFields
            )
        } catch let error as NetworkError {
            throw error
        } catch let error as URLError {
            switch error.code {
            case .timedOut:
                throw NetworkError.timeout
            case .notConnectedToInternet, .networkConnectionLost:
                throw NetworkError.networkUnavailable
            case .cannotConnectToHost:
                throw NetworkError.connectionRefused
            default:
                throw NetworkError.unknown(error)
            }
        } catch {
            throw NetworkError.unknown(error)
        }
    }
}

// MARK: - Cloud API Client

class CloudAPIClient {
    
    private let httpClient: HTTPClient
    private let baseURL: String
    private var authToken: String?
    
    init(
        baseURL: String = "https://api.example.com",
        httpClient: HTTPClient = HTTPClient()
    ) {
        self.baseURL = baseURL
        self.httpClient = httpClient
    }
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    private var authHeaders: [String: String] {
        var headers: [String: String] = [:]
        if let token = authToken {
            headers["Authorization"] = "Bearer \(token)"
        }
        return headers
    }
    
    // MARK: - Device Registration
    
    struct DeviceRegistration: Codable {
        let deviceId: String
        let deviceName: String
        let deviceType: String
        let localIpAddress: String
    }
    
    struct RegisteredDevice: Codable {
        let id: String
        let deviceId: String
        let deviceName: String
        let deviceType: String
        let localIpAddress: String
        let registeredAt: Date?
    }
    
    func registerDevice(_ device: DeviceRegistration) async throws -> RegisteredDevice {
        let encoder = JSONEncoder()
        encoder.keyEncodingStrategy = .convertToSnakeCase
        let body = try encoder.encode(device)
        
        let response = try await httpClient.request(
            url: "\(baseURL)/v1/devices",
            method: .post,
            headers: authHeaders,
            body: body,
            responseType: RegisteredDevice.self
        )
        return response.data
    }
    
    func getDevices() async throws -> [RegisteredDevice] {
        let response = try await httpClient.request(
            url: "\(baseURL)/v1/devices",
            method: .get,
            headers: authHeaders,
            body: nil,
            responseType: [RegisteredDevice].self
        )
        return response.data
    }
    
    // MARK: - Telemetry
    
    struct TelemetryData: Codable {
        let deviceId: String
        let timestamp: Date
        let metrics: [String: Double]
    }
    
    func sendTelemetry(_ telemetry: TelemetryData) async throws {
        let encoder = JSONEncoder()
        encoder.keyEncodingStrategy = .convertToSnakeCase
        encoder.dateEncodingStrategy = .iso8601
        let body = try encoder.encode(telemetry)
        
        _ = try await httpClient.requestRaw(
            url: "\(baseURL)/v1/telemetry",
            method: .post,
            headers: authHeaders,
            body: body
        )
    }
    
    // MARK: - Firmware
    
    struct FirmwareInfo: Codable {
        let version: String
        let downloadUrl: String
        let checksum: String
        let releaseNotes: String?
    }
    
    func checkFirmwareUpdate(deviceType: String, currentVersion: String) async throws -> FirmwareInfo? {
        let response = try await httpClient.request(
            url: "\(baseURL)/v1/firmware/\(deviceType)?current_version=\(currentVersion)",
            method: .get,
            headers: authHeaders,
            body: nil,
            responseType: FirmwareInfo.self
        )
        return response.data
    }
}

// MARK: - IoT Device Client

class IoTDeviceClient {
    
    private let httpClient: HTTPClient
    
    init(httpClient: HTTPClient = HTTPClient()) {
        self.httpClient = httpClient
    }
    
    // MARK: - Device Models
    
    struct DeviceStatus: Codable {
        let deviceId: String
        let online: Bool
        let uptime: Int
        let firmwareVersion: String
        let sensors: [SensorReading]?
    }
    
    struct SensorReading: Codable {
        let name: String
        let value: Double
        let unit: String
        let timestamp: String?
    }
    
    struct DeviceCommand: Codable {
        let command: String
        let parameters: [String: String]?
    }
    
    struct CommandResponse: Codable {
        let success: Bool
        let message: String?
        let data: [String: String]?
    }
    
    struct DeviceConfig: Codable {
        let settings: [String: String]
    }
    
    // MARK: - Device Discovery
    
    /// Attempts to discover devices on the local network by scanning common ports
    func discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        range: ClosedRange<Int> = 1...254
    ) async -> [String] {
        var discoveredDevices: [String] = []
        
        await withTaskGroup(of: String?.self) { group in
            for i in range {
                let ip = "\(subnet).\(i)"
                group.addTask { [weak self] in
                    guard let self = self else { return nil }
                    do {
                        let url = "http://\(ip):\(port)/status"
                        _ = try await self.httpClient.requestRaw(url: url, method: .get)
                        return ip
                    } catch {
                        return nil
                    }
                }
            }
            
            for await result in group {
                if let ip = result {
                    discoveredDevices.append(ip)
                }
            }
        }
        
        return discoveredDevices
    }
    
    // MARK: - Device Status
    
    func getDeviceStatus(host: String, port: Int = 80) async throws -> DeviceStatus {
        let scheme = port == 443 ? "https" : "http"
        let url = "\(scheme)://\(host):\(port)/status"
        
        let response = try await httpClient.request(
            url: url,
            method: .get,
            headers: nil,
            body: nil,
            responseType: DeviceStatus.self
        )
        return response.data
    }
    
    // MARK: - Send Command
    
    func sendCommand(
        host: String,
        port: Int = 80,
        command: DeviceCommand
    ) async throws -> CommandResponse {
        let scheme = port == 443 ? "https" : "http"
        let url = "\(scheme)://\(host):\(port)/command"
        
        let encoder = JSONEncoder()
        let body = try encoder.encode(command)
        
        let response = try await httpClient.request(
            url: url,
            method: .post,
            headers: nil,
            body: body,
            responseType: CommandResponse.self
        )
        return response.data
    }
    
    // MARK: - Sensor Data
    
    func getSensorData(host: String, port: Int = 80) async throws -> [SensorReading] {
        let scheme = port == 443 ? "https" : "http"
        let url = "\(scheme)://\(host):\(port)/sensors"
        
        let response = try await httpClient.request(
            url: url,
            method: .get,
            headers: nil,
            body: nil,
            responseType: [SensorReading].self
        )
        return response.data
    }
    
    // MARK: - Device Configuration
    
    func getDeviceConfig(host: String, port: Int = 80) async throws -> DeviceConfig {
        let scheme = port == 443 ? "https" : "http"
        let url = "\(scheme)://\(host):\(port)/config"
        
        let response = try await httpClient.request(
            url: url,
            method: .get,
            headers: nil,
            body: nil,
            responseType: DeviceConfig.self
        )
        return response.data
    }
    
    func updateDeviceConfig(
        host: String,
        port: Int = 80,
        config: DeviceConfig
    ) async throws -> CommandResponse {
        let scheme = port == 443 ? "https" : "http"
        let url = "\(scheme)://\(host):\(port)/config"
        
        let encoder = JSONEncoder()
        let body = try encoder.encode(config)
        
        let response = try await httpClient.request(
            url: url,
            method: .put,
            headers: nil,
            body: body,
            responseType: CommandResponse.self
        )
        return response.data
    }
    
    // MARK: - Firmware Update (to device)
    
    func triggerFirmwareUpdate(
        host: String,
        port: Int = 80,
        firmwareURL: String,
        checksum: String
    ) async throws -> CommandResponse {
        let command = DeviceCommand(
            command: "firmware_update",
            parameters: [
                "url": firmwareURL,
                "checksum": checksum
            ]
        )
        return try await sendCommand(host: host, port: port, command: command)
    }
    
    // MARK: - Ping / Health Check
    
    func ping(host: String, port: Int = 80) async -> Bool {
        let scheme = port == 443 ? "https" : "http"
        let url = "\(scheme)://\(host):\(port)/ping"
        
        do {
            _ = try await httpClient.requestRaw(url: url, method: .get)
            return true
        } catch {
            return false
        }
    }
}

// MARK: - Unified Device Manager

class DeviceManager {
    
    let cloudClient: CloudAPIClient
    let iotClient: IoTDeviceClient
    
    init(
        cloudClient: CloudAPIClient = CloudAPIClient(),
        iotClient: IoTDeviceClient = IoTDeviceClient()
    ) {
        self.cloudClient = cloudClient
        self.iotClient = iotClient
    }
    
    struct ManagedDevice {
        let registeredDevice: CloudAPIClient.RegisteredDevice
        var localStatus: IoTDeviceClient.DeviceStatus?
        var isReachable: Bool
    }
    
    /// Fetches devices from cloud and checks local availability
    func getAllDevicesWithStatus() async throws -> [ManagedDevice] {
        let registeredDevices = try await cloudClient.getDevices()
        
        var managedDevices: [ManagedDevice] = []
        
        await withTaskGroup(of: ManagedDevice.self) { group in
            for device in registeredDevices {
                group.addTask { [weak self] in
                    guard let self = self else {
                        return ManagedDevice(
                            registeredDevice: device,
                            localStatus: nil,
                            isReachable: false
                        )
                    }
                    
                    do {
                        let status = try await self.iotClient.getDeviceStatus(
                            host: device.localIpAddress
                        )
                        return ManagedDevice(
                            registeredDevice: device,
                            localStatus: status,
                            isReachable: true
                        )
                    } catch {
                        return ManagedDevice(
                            registeredDevice: device,
                            localStatus: nil,
                            isReachable: false
                        )
                    }
                }
            }
            
            for await managed in group {
                managedDevices.append(managed)
            }
        }
        
        return managedDevices
    }
    
    /// Collects telemetry from a local device and forwards it to the cloud
    func collectAndForwardTelemetry(
        host: String,
        deviceId: String
    ) async throws {
        let sensorData = try await iotClient.getSensorData(host: host)
        
        var metrics: [String: Double] = [:]
        for reading in sensorData {
            metrics[reading.name] = reading.value
        }
        
        let telemetry = CloudAPIClient.TelemetryData(
            deviceId: deviceId,
            timestamp: Date(),
            metrics: metrics
        )
        
        try await cloudClient.sendTelemetry(telemetry)
    }
    
    /// Checks for firmware updates and triggers OTA update on the device
    func checkAndUpdateFirmware(
        host: String,
        deviceType: String,
        currentVersion: String
    ) async throws -> Bool {
        guard let firmwareInfo = try await cloudClient.checkFirmwareUpdate(
            deviceType: deviceType,
            currentVersion: currentVersion
        ) else {
            return false // No update available
        }
        
        let response = try await iotClient.triggerFirmwareUpdate(
            host: host,
            firmwareURL: firmwareInfo.downloadUrl,
            checksum: firmwareInfo.checksum
        )
        
        return response.success
    }
}

