// MARK: - Usage Example

func exampleUsage() async {
    let manager = DeviceManager()
    
    // Authenticate with cloud
    manager.cloudClient.setAuthToken("your-jwt-token-here")
    
    // --- Cloud API (HTTPS) ---
    do {
        // Register a new device
        let registration = CloudAPIClient.DeviceRegistration(
            deviceId: "sensor-001",
            deviceName: "Living Room Sensor",
            deviceType: "temperature_sensor",
            localIpAddress: "192.168.1.50"
        )
        let registered = try await manager.cloudClient.registerDevice(registration)
        print("Registered device: \(registered.id)")
    } catch {
        print("Cloud error: \(error.localizedDescription)")
    }
    
    // --- Local IoT Device (HTTP) ---
    do {
        // Check if device is reachable
        let isOnline = await manager.iotClient.ping(host: "192.168.1.50")
        print("Device online: \(isOnline)")
        
        if isOnline {
            // Get device status
            let status = try await manager.iotClient.getDeviceStatus(host: "192.168.1.50")
            print("Device uptime: \(status.uptime)s, firmware: \(status.firmwareVersion)")
            
            // Send a command
            let command = IoTDeviceClient.DeviceCommand(
                command: "set_led",
                parameters: ["color": "green", "brightness": "80"]
            )
            let response = try await manager.iotClient.sendCommand(
                host: "192.168.1.50",
                command: command
            )
            print("Command result: \(response.success)")
            
            // Read sensor data
            let sensors = try await manager.iotClient.getSensorData(host: "192.168.1.50")
            for sensor in sensors {
                print("\(sensor.name): \(sensor.value) \(sensor.unit)")
            }
        }
    } catch {
        print("IoT error: \(error.localizedDescription)")
    }
    
    // --- Combined Operations ---
    do {
        // Get all devices with their local status
        let devices = try await manager.getAllDevicesWithStatus()
        for device in devices {
            print("\(device.registeredDevice.deviceName) - Reachable: \(device.isReachable)")
        }
        
        // Collect telemetry and forward to cloud
        try await manager.collectAndForwardTelemetry(
            host: "192.168.1.50",
            deviceId: "sensor-001"
        )
        
        // Check and apply firmware updates
        let updated = try await manager.checkAndUpdateFirmware(
            host: "192.168.1.50",
            deviceType: "temperature_sensor",
            currentVersion: "1.2.0"
        )
        print("Firmware updated: \(updated)")
    } catch {
        print("Error: \(error.localizedDescription)")
    }
    
    // --- Device Discovery ---
    do {
        let discoveredIPs = await manager.iotClient.discoverDevices(
            subnet: "192.168.1",
            port: 80,
            range: 1...50  // Scan first 50 addresses
        )
        print("Discovered devices at: \(discoveredIPs)")
    }
}